import pytest
from source import subsequences

def test_base_case_returns_empty_subsequence():
    """The base case k == 0 should return a list containing the empty subsequence."""
    result = subsequences(1, 5, 0)
    assert result == [[]], f"Expected [[ ]], got {result}"

def test_combinations_length_and_membership():
    """For range 1 to 5 (exclusive of 5) and k=2, there should be C(4,2)=6 combinations."""
    result = subsequences(1, 5, 2)
    expected = [
        [1, 2], [1, 3], [1, 4],
        [2, 3], [2, 4], [3, 4]
    ]
    assert len(result) == len(expected), (
        f"Expected {len(expected)} combinations, got {len(result)}"
    )
    for comb in expected:
        assert comb in result, (
            f"Missing expected combination {comb} in result {result}"
        )
